def most_common(numbers):
    count = {}
    for num in numbers:
        if num not in count:
            count[num] = 1
        else:
            count[num] += 1
    best = None
    best_count = 0
    for num, times in count.items():
        if times > best_count:
            best_count = times
            best = num
    return best

