SELECT DISTINCT city
FROM users;

-- DISTINCT removes duplicate rows

SELECT city, COUNT(*) AS user_count
FROM users
GROUP BY city;

SELECT *
FROM users
WHERE salary > (
  SELECT AVG(salary)
  FROM users
);

SELECT name, dept, salary,
  RANK() OVER (
    PARTITION BY dept
    ORDER BY salary DESC
  ) AS salary_rank
FROM employees;

SELECT date, amount,
  SUM(amount) OVER (
    ORDER BY date
  ) AS running_total
FROM sales;

DELETE FROM users
WHERE id NOT IN (
  SELECT MIN(id)
  FROM users
  GROUP BY email
);

WITH ranked AS (
  SELECT *,
    ROW_NUMBER() OVER (
      PARTITION BY customer_id
      ORDER BY order_date DESC
    ) AS rn
  FROM orders
)
SELECT * FROM ranked WHERE rn = 1;

ROW_NUMBER + PARTITION = pick one per group

